INSERT INTO "teams" ("id","created_by","name","description","avatar_seed","leader_agent_id","default_mode_id","is_template") VALUES (
  '56e82e7e-c79e-4ed4-953c-f6334b186a82',
  NULL,
  '辩论赛',
  '给出一个议题,三方轮流发言——乐观派看见机会,质疑者索取证据,务实派追问落地路径。三个视角互补,在你关心的任何话题上展开一场结构化的圆桌辩论。',
  'debate-team',
  NULL,
  'roundtable',
  true
) ON CONFLICT ("id") DO NOTHING;

INSERT INTO "teams" ("id","created_by","name","description","avatar_seed","leader_agent_id","default_mode_id","is_template") VALUES (
  '0dc0da5e-9384-4a02-9d87-585f7a1cc04c',
  NULL,
  '当皇帝',
  '陛下，朕乃大唐天子，三省六部九位重臣列于丹墀之下，恭候圣裁。您即是皇帝本人——欲颁一道诏令、征询一桩国策，或抛出难解之局（如「朕欲征南诏，诸卿以为如何」），群臣便会按职各抒己见、相互驳难、朋党试探。三省六部结构灵感来自 [wanikua/danghuangshang](https://github.com/wanikua/danghuangshang) (MIT)，但本团队每位大臣皆依贞观、开元之制重塑，有独立声口与史料根基。',
  'huangdi-court',
  NULL,
  'open-chat',
  true
) ON CONFLICT ("id") DO NOTHING;

INSERT INTO "teams" ("id","created_by","name","description","avatar_seed","leader_agent_id","default_mode_id","is_template") VALUES (
  '9d8ce351-74ab-41fa-a359-146a881f22a3',
  NULL,
  '投资团队',
  '一个由 CFO 带队的六人投研小组，覆盖量化、风控、宏观、行业与反方视角。抛出一个标的、一个宏观假设、或一个尽调结果，他们会立刻分头拆解、互相质疑，最后拍出一个可执行的仓位建议。',
  'investment-team',
  'b4dd56d1-613c-46ed-b5a2-2a06b9f13e22',
  'open-chat',
  true
) ON CONFLICT ("id") DO NOTHING;

INSERT INTO "teams" ("id","created_by","name","description","avatar_seed","leader_agent_id","default_mode_id","is_template") VALUES (
  'b9c0883a-61a0-47f6-820d-f16edf19823c',
  NULL,
  '狼人杀',
  '九个性格迥异的玩家围坐一桌，准备一场经典的九人局狼人杀。请注意：这九份人设描写的是他们的发言风格与打牌习惯，而不是具体身份——狼、预言家、女巫、猎人、村民的角色会在对局开始时随机分配，同一个人设在不同局里可能是好人也可能是狼。',
  'werewolf-table',
  NULL,
  'werewolf',
  true
) ON CONFLICT ("id") DO NOTHING;

